function makeRequest(parsedUrl) {
  return new Promise((resolve, reject) => {
    const transport = parsedUrl.protocol === 'https:' ? https : http;

    const options = {
      hostname: parsedUrl.hostname,
      port: parsedUrl.port || (parsedUrl.protocol === 'https:' ? 443 : 80),
      path: parsedUrl.pathname + parsedUrl.search,
      method: 'GET',
      timeout: REQUEST_TIMEOUT_MS,
      headers: {
        'User-Agent': 'WebhookProxy/1.0',
        'Accept': '*/*',
      },
      // Critical: do not follow redirects automatically
      // Node's http/https modules don't follow redirects by default, which is what we want
    };

    const req = transport.request(options, (res) => {
      // Block redirects to prevent SSRF via redirect
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        req.destroy();
        reject(new Error(`Redirects are not allowed (received ${res.statusCode} to ${res.headers.location}). Provide the final destination URL directly.`));
        return;
      }

      const chunks = [];
      let totalSize = 0;

      res.on('data', (chunk) => {
        totalSize += chunk.length;
        if (totalSize > MAX_RESPONSE_SIZE) {
          req.destroy();
          reject(new Error(`Response exceeds maximum allowed size of ${MAX_RESPONSE_SIZE} bytes`));
          return;
        }
        chunks.push(chunk);
      });

      res.on('end', () => {
        resolve({
          statusCode: res.statusCode,
          headers: res.headers,
          body: Buffer.concat(chunks),
        });
      });

      res.on('error', (err) => {
        reject(new Error(`Response error: ${err.message}`));
      });
    });

    req.on('timeout', () => {
      req.destroy();
      reject(new Error(`Request timed out after ${REQUEST_TIMEOUT_MS}ms`));
    });

    req.on('error', (err) => {
      reject(new Error(`Request error: ${err.message}`));
    });

    req.end();
  });
}

